// API基础URL
const API_BASE_URL = 'http://localhost:5000/api';

// 全局状态
let todos = [];
let currentFilter = 'all';

// DOM加载完成后执行
document.addEventListener('DOMContentLoaded', () => {
    loadTodos();
    setupEventListeners();
});

// 设置事件监听器
function setupEventListeners() {
    // 添加待办事项
    document.getElementById('addTodoBtn').addEventListener('click', addTodo);
    document.getElementById('todoTitle').addEventListener('keypress', (e) => {
        if (e.key === 'Enter') addTodo();
    });

    // 过滤器
    document.querySelectorAll('.filter-btn').forEach(btn => {
        btn.addEventListener('click', () => {
            document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
            btn.classList.add('active');
            currentFilter = btn.dataset.filter;
            renderTodos();
        });
    });

    // 模态框
    document.querySelector('.close').addEventListener('click', closeModal);
    document.getElementById('cancelEdit').addEventListener('click', closeModal);
    document.getElementById('saveEdit').addEventListener('click', saveEdit);

    // 点击模态框外部关闭
    window.addEventListener('click', (e) => {
        const modal = document.getElementById('editModal');
        if (e.target === modal) closeModal();
    });
}

// 加载所有待办事项
async function loadTodos() {
    try {
        showLoading();
        const response = await fetch(`${API_BASE_URL}/todos`);
        const result = await response.json();

        if (result.success) {
            todos = result.data;
            renderTodos();
            updateStats();
        } else {
            showError('加载待办事项失败');
        }
    } catch (error) {
        console.error('Error loading todos:', error);
        showError('网络错误，请确保服务器正在运行');
    }
}

// 添加新的待办事项
async function addTodo() {
    const titleInput = document.getElementById('todoTitle');
    const descInput = document.getElementById('todoDescription');

    const title = titleInput.value.trim();
    const description = descInput.value.trim();

    if (!title) {
        alert('请输入待办事项标题');
        return;
    }

    try {
        const response = await fetch(`${API_BASE_URL}/todos`, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ title, description })
        });

        const result = await response.json();

        if (result.success) {
            todos.unshift(result.data);
            renderTodos();
            updateStats();

            // 清空输入框
            titleInput.value = '';
            descInput.value = '';
        } else {
            showError(result.message || '添加失败');
        }
    } catch (error) {
        console.error('Error adding todo:', error);
        showError('网络错误');
    }
}

// 切换待办事项完成状态
async function toggleTodo(todoId) {
    try {
        const response = await fetch(`${API_BASE_URL}/todos/${todoId}/toggle`, {
            method: 'POST'
        });

        const result = await response.json();

        if (result.success) {
            const index = todos.findIndex(t => t.id === todoId);
            if (index !== -1) {
                todos[index] = result.data;
                renderTodos();
                updateStats();
            }
        }
    } catch (error) {
        console.error('Error toggling todo:', error);
        showError('操作失败');
    }
}

// 删除待办事项
async function deleteTodo(todoId) {
    if (!confirm('确定要删除这个待办事项吗？')) {
        return;
    }

    try {
        const response = await fetch(`${API_BASE_URL}/todos/${todoId}`, {
            method: 'DELETE'
        });

        const result = await response.json();

        if (result.success) {
            todos = todos.filter(t => t.id !== todoId);
            renderTodos();
            updateStats();
        } else {
            showError(result.message || '删除失败');
        }
    } catch (error) {
        console.error('Error deleting todo:', error);
        showError('删除失败');
    }
}

// 打开编辑模态框
function openEditModal(todoId) {
    const todo = todos.find(t => t.id === todoId);
    if (!todo) return;

    document.getElementById('editTodoId').value = todo.id;
    document.getElementById('editTitle').value = todo.title;
    document.getElementById('editDescription').value = todo.description || '';

    document.getElementById('editModal').style.display = 'block';
}

// 关闭模态框
function closeModal() {
    document.getElementById('editModal').style.display = 'none';
}

// 保存编辑
async function saveEdit() {
    const todoId = parseInt(document.getElementById('editTodoId').value);
    const title = document.getElementById('editTitle').value.trim();
    const description = document.getElementById('editDescription').value.trim();

    if (!title) {
        alert('标题不能为空');
        return;
    }

    try {
        const response = await fetch(`${API_BASE_URL}/todos/${todoId}`, {
            method: 'PUT',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({ title, description })
        });

        const result = await response.json();

        if (result.success) {
            const index = todos.findIndex(t => t.id === todoId);
            if (index !== -1) {
                todos[index] = result.data;
                renderTodos();
            }
            closeModal();
        } else {
            showError(result.message || '保存失败');
        }
    } catch (error) {
        console.error('Error saving todo:', error);
        showError('保存失败');
    }
}

// 渲染待办事项列表
function renderTodos() {
    const todoList = document.getElementById('todoList');

    let filteredTodos = todos;
    if (currentFilter === 'active') {
        filteredTodos = todos.filter(t => !t.completed);
    } else if (currentFilter === 'completed') {
        filteredTodos = todos.filter(t => t.completed);
    }

    if (filteredTodos.length === 0) {
        todoList.innerHTML = '<div class="loading">暂无待办事项</div>';
        return;
    }

    todoList.innerHTML = filteredTodos.map(todo => `
        <div class="todo-item ${todo.completed ? 'completed' : ''}" data-id="${todo.id}">
            <div class="todo-header">
                <div style="display: flex; align-items: center; flex: 1;">
                    <input 
                        type="checkbox" 
                        class="todo-checkbox" 
                        ${todo.completed ? 'checked' : ''} 
                        onchange="toggleTodo(${todo.id})"
                    >
                    <span class="todo-title">${escapeHtml(todo.title)}</span>
                </div>
                <div class="todo-actions">
                    <button class="btn btn-edit" onclick="openEditModal(${todo.id})">编辑</button>
                    <button class="btn btn-danger" onclick="deleteTodo(${todo.id})">删除</button>
                </div>
            </div>
            ${todo.description ? `<div class="todo-description">${escapeHtml(todo.description)}</div>` : ''}
            <div class="todo-meta">创建于: ${formatDate(todo.created_at)}</div>
        </div>
    `).join('');
}

// 更新统计信息
function updateStats() {
    const total = todos.length;
    const completed = todos.filter(t => t.completed).length;
    const active = total - completed;

    document.getElementById('totalCount').innerHTML = `总任务: <strong>${total}</strong>`;
    document.getElementById('completedCount').innerHTML = `已完成: <strong>${completed}</strong>`;
    document.getElementById('activeCount').innerHTML = `未完成: <strong>${active}</strong>`;
}

// 显示加载状态
function showLoading() {
    document.getElementById('todoList').innerHTML = '<div class="loading">加载中...</div>';
}

// 显示错误信息
function showError(message) {
    const todoList = document.getElementById('todoList');
    todoList.innerHTML = `<div class="error-message">${message}</div>`;
    setTimeout(() => {
        if (todos.length === 0) {
            todoList.innerHTML = '<div class="loading">暂无待办事项</div>';
        } else {
            renderTodos();
        }
    }, 3000);
}

// 格式化日期
function formatDate(dateString) {
    const date = new Date(dateString);
    const now = new Date();
    const diffTime = Math.abs(now - date);
    const diffDays = Math.floor(diffTime / (1000 * 60 * 60 * 24));

    if (diffDays === 0) {
        return '今天';
    } else if (diffDays === 1) {
        return '昨天';
    } else if (diffDays < 7) {
        return `${diffDays} 天前`;
    } else {
        return date.toLocaleDateString('zh-CN');
    }
}

// HTML转义
function escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
}

