from flask import Flask, jsonify, request, send_from_directory
from flask_cors import CORS
import sys
import os

sys.path.append(os.path.dirname(os.path.abspath(__file__)))
from database import init_db, get_all_todos, get_todo_by_id, create_todo, update_todo, delete_todo

app = Flask(__name__, static_folder='../frontend', static_url_path='')
CORS(app)

# Initialize database
init_db()

@app.route('/')
def index():
    return send_from_directory('../frontend', 'index.html')

@app.route('/api/todos', methods=['GET'])
def api_get_todos():
    todos = get_all_todos()
    return jsonify({'success': True, 'data': todos})

@app.route('/api/todos', methods=['POST'])
def api_create_todo():
    data = request.get_json()
    title = data.get('title')
    description = data.get('description', '')

    if not title:
        return jsonify({'success': False, 'message': '标题不能为空'}), 400

    todo_id = create_todo(title, description)
    todo = get_todo_by_id(todo_id)
    return jsonify({'success': True, 'data': todo}), 201

@app.route('/api/todos/<int:todo_id>', methods=['PUT', 'PATCH'])
def api_update_todo(todo_id):
    data = request.get_json()

    title = data.get('title')
    description = data.get('description')
    completed = data.get('completed')

    if update_todo(todo_id, title=title, description=description, completed=completed):
        todo = get_todo_by_id(todo_id)
        return jsonify({'success': True, 'data': todo})
    else:
        return jsonify({'success': False, 'message': '待办事项不存在'}), 404

@app.route('/api/todos/<int:todo_id>', methods=['DELETE'])
def api_delete_todo(todo_id):
    if delete_todo(todo_id):
        return jsonify({'success': True, 'message': '删除成功'})
    else:
        return jsonify({'success': False, 'message': '待办事项不存在'}), 404

@app.route('/api/todos/<int:todo_id>/toggle', methods=['POST'])
def api_toggle_todo(todo_id):
    todo = get_todo_by_id(todo_id)

    if not todo:
        return jsonify({'success': False, 'message': '待办事项不存在'}), 404

    new_status = not todo['completed']
    if update_todo(todo_id, completed=new_status):
        updated_todo = get_todo_by_id(todo_id)
        return jsonify({'success': True, 'data': updated_todo})

    return jsonify({'success': False, 'message': '更新失败'}), 500

# Error handlers
@app.errorhandler(404)
def not_found(error):
    return jsonify({'success': False, 'message': '请求的资源不存在'}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({'success': False, 'message': '服务器内部错误'}), 500

if __name__ == '__main__':
    print("启动TODO-List服务器...")
    print("访问地址: http://localhost:5000")
    # 禁用调试模式和重载器，避免watchdog冲突
    app.run(debug=False, host='0.0.0.0', port=5000, use_reloader=False)
